package com.example.biometricauth;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;

public class LoginActivity extends AppCompatActivity {

    private EditText usernameEt;
    private EditText passwordEt;
    private Button loginBtn;
    private Button biometricUnlockBtn;
    private CheckBox enableBiometricCb;
    private TextView statusTv;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        usernameEt = findViewById(R.id.usernameEt);
        passwordEt = findViewById(R.id.passwordEt);
        loginBtn = findViewById(R.id.loginBtn);
        biometricUnlockBtn = findViewById(R.id.biometricUnlockBtn);
        enableBiometricCb = findViewById(R.id.enableBiometricCb);
        statusTv = findViewById(R.id.statusTv);

        enableBiometricCb.setChecked(BiometricAuthManager.Prefs.isBiometricEnabled(this));
        updateBiometricUi();

        enableBiometricCb.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (!isChecked) {
                BiometricAuthManager.Prefs.setBiometricEnabled(this, false);
                updateBiometricUi();
                return;
            }

            int can = BiometricAuthManager.canAuthenticate(this);
            if (can != BiometricManager.BIOMETRIC_SUCCESS) {
                enableBiometricCb.setChecked(false);
                BiometricAuthManager.Prefs.setBiometricEnabled(this, false);
                statusTv.setText("Biometric not available");
                updateBiometricUi();
                return;
            }

            BiometricAuthManager.authenticate(
                    this,
                    "Enable biometric login",
                    "Authenticate to enable",
                    "Cancel",
                    new BiometricAuthManager.AuthCallback() {
                        @Override
                        public void onAuthenticated() {
                            BiometricAuthManager.Prefs.setBiometricEnabled(LoginActivity.this, true);
                            statusTv.setText("Biometric login enabled");
                            updateBiometricUi();
                        }

                        @Override
                        public void onFailed() {
                            statusTv.setText("Not recognized. Try again.");
                        }

                        @Override
                        public void onError(int errorCode, @NonNull CharSequence errString) {
                            enableBiometricCb.setChecked(false);
                            BiometricAuthManager.Prefs.setBiometricEnabled(LoginActivity.this, false);
                            statusTv.setText(errString);
                            updateBiometricUi();
                        }

                        @Override
                        public void onNotAvailable(int canAuthenticateCode) {
                            enableBiometricCb.setChecked(false);
                            BiometricAuthManager.Prefs.setBiometricEnabled(LoginActivity.this, false);
                            statusTv.setText("Biometric not available");
                            updateBiometricUi();
                        }
                    }
            );
        });

        biometricUnlockBtn.setOnClickListener(v -> BiometricAuthManager.authenticate(
                this,
                "Unlock",
                "Use fingerprint to login",
                "Use password",
                new BiometricAuthManager.AuthCallback() {
                    @Override
                    public void onAuthenticated() {
                        goToHome();
                    }

                    @Override
                    public void onFailed() {
                        statusTv.setText("Not recognized. Try again.");
                    }

                    @Override
                    public void onError(int errorCode, @NonNull CharSequence errString) {
                        statusTv.setText(errString);
                    }

                    @Override
                    public void onNotAvailable(int canAuthenticateCode) {
                        statusTv.setText("Biometric not available");
                    }
                }
        ));

        loginBtn.setOnClickListener(v -> {
            if (validatePasswordLogin()) {
                statusTv.setText("");
                goToHome();
            } else {
                statusTv.setText("Invalid username or password");
            }
        });
    }

    @Override
    protected void onResume() {
        super.onResume();
        BiometricAuthManager.authenticateIfEnabledOrContinue(
                this,
                HomeActivity.class,
                () -> {
                    updateBiometricUi();
                }
        );
    }

    private void updateBiometricUi() {
        boolean enabled = BiometricAuthManager.Prefs.isBiometricEnabled(this);
        int can = BiometricAuthManager.canAuthenticate(this);
        boolean available = can == BiometricManager.BIOMETRIC_SUCCESS;

        biometricUnlockBtn.setEnabled(enabled && available);
        biometricUnlockBtn.setVisibility((enabled && available) ? View.VISIBLE : View.GONE);

        if (!available && enabled) {
            BiometricAuthManager.Prefs.setBiometricEnabled(this, false);
            enableBiometricCb.setChecked(false);
        }
    }

    private boolean validatePasswordLogin() {
        String u = usernameEt.getText() != null ? usernameEt.getText().toString() : "";
        String p = passwordEt.getText() != null ? passwordEt.getText().toString() : "";
        return !u.trim().isEmpty() && p.length() >= 4;
    }

    private void goToHome() {
        startActivity(new Intent(this, HomeActivity.class));
        finish();
    }
}

package com.example.biometricauth;

import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private TextView infoTv;
    private Button logoutBtn;
    private Button disableBiometricBtn;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        infoTv = findViewById(R.id.infoTv);
        logoutBtn = findViewById(R.id.logoutBtn);
        disableBiometricBtn = findViewById(R.id.disableBiometricBtn);

        infoTv.setText("Unlocked");

        disableBiometricBtn.setOnClickListener(v -> {
            BiometricAuthManager.Prefs.setBiometricEnabled(this, false);
            infoTv.setText("Biometric login disabled");
        });

        logoutBtn.setOnClickListener(v -> {
            finish();
        });
    }
}

